function setTempAdminPassword($new_password_1, $new_password_2, $save_config = true)
{
    global $config;

    settype($old_password, 'string');
    settype($new_password_1, 'string');
    settype($new_password_2, 'string');
    $new_password_1 = trim($new_password_1);
